    private func formatLogMessage(_ data: AnalyticsData) -> String {
        let timestamp = data.timestamp.formatted(date: .complete, time: .complete)
        let userId = data.userId ?? "unknown"
        let userEmail = data.userEmail ?? "unknown"
        
        let payloadString = data.payload.map { key, value in
            "\(key): \(String(describing: value))"
        }.joined(separator: ", ")
        
        return "[Analytics] \(timestamp) | Session: \(data.sessionId) | User: \(userId) | Email: \(userEmail) | Event: \(data.eventType.rawValue) | Payload: { \(payloadString) }"
